import type { Quiz, QuizQuestion, QuestionAttemptResult } from '../types/quiz';

/** Callback when the quiz is completed with all attempt results. */
export type OnQuizComplete = (results: QuestionAttemptResult[]) => void;

/** Callback when the user wants to go back to home. */
export type OnQuizExit = () => void;

/** State of a single question during the quiz. */
export interface QuestionState {
  attempts: string[];
  resolved: boolean;
}

interface QuizPlayerState {
  currentIndex: number;
  questions: Partial<Record<string, QuestionState>>;
  maxAttempts: number;
}

const MAX_ATTEMPTS = 3;

function getQuestionState(state: QuizPlayerState, questionId: string): QuestionState {
  const existing = state.questions[questionId];
  if (existing) {
    return existing;
  }
  const newState: QuestionState = { attempts: [], resolved: false };
  state.questions[questionId] = newState;
  return newState;
}

function countResolved(state: QuizPlayerState): number {
  return Object.values(state.questions).filter((q) => q?.resolved).length;
}

function countUnresolved(quiz: Quiz, state: QuizPlayerState): number {
  return quiz.questions.length - countResolved(state);
}

function findFirstUnresolvedIndex(quiz: Quiz, state: QuizPlayerState): number {
  return Math.max(0, quiz.questions.findIndex((q) => !state.questions[q.id]?.resolved));
}

/**
 * Render the quiz player into the given container.
 * Manages question navigation, answer selection, and completion.
 */
export function renderQuizPlayer(
  container: HTMLElement,
  quiz: Quiz,
  onComplete: OnQuizComplete,
  onExit: OnQuizExit,
): void {
  const state: QuizPlayerState = {
    currentIndex: 0,
    questions: {},
    maxAttempts: MAX_ATTEMPTS,
  };

  function render(): void {
    container.innerHTML = '';

    const wrapper = document.createElement('div');
    wrapper.className = 'quiz-player';

    const header = createHeader(quiz, state, onExit);
    wrapper.appendChild(header);

    const question = quiz.questions[state.currentIndex];
    const questionEl = createQuestion(question, state, () => { render(); });
    wrapper.appendChild(questionEl);

    const nav = createNavigation(quiz, state, onComplete, () => { render(); });
    wrapper.appendChild(nav);

    container.appendChild(wrapper);
  }

  render();
}

function createHeader(quiz: Quiz, state: QuizPlayerState, onExit: OnQuizExit): HTMLElement {
  const header = document.createElement('header');
  header.className = 'quiz-header';

  const exitBtn = document.createElement('button');
  exitBtn.className = 'btn btn-ghost quiz-exit-btn';
  exitBtn.textContent = 'Zpět';
  exitBtn.addEventListener('click', onExit);

  const titleEl = document.createElement('h2');
  titleEl.className = 'quiz-title';
  titleEl.textContent = quiz.title;

  const progress = document.createElement('div');
  progress.className = 'quiz-progress';

  const progressBar = document.createElement('div');
  progressBar.className = 'quiz-progress-bar';

  const resolvedCount = countResolved(state);
  const percent = (resolvedCount / quiz.questions.length) * 100;
  progressBar.style.width = `${String(percent)}%`;

  progress.appendChild(progressBar);

  const counter = document.createElement('span');
  counter.className = 'quiz-counter';
  counter.textContent = `${String(state.currentIndex + 1)} / ${String(quiz.questions.length)}`;

  header.appendChild(exitBtn);
  header.appendChild(titleEl);
  header.appendChild(progress);
  header.appendChild(counter);

  return header;
}

function createQuestion(
  question: QuizQuestion,
  state: QuizPlayerState,
  rerender: () => void,
): HTMLElement {
  const section = document.createElement('section');
  section.className = 'quiz-question';

  const questionText = document.createElement('h3');
  questionText.className = 'quiz-question-text';
  questionText.textContent = question.question;
  section.appendChild(questionText);

  const answersGrid = document.createElement('div');
  answersGrid.className = 'quiz-answers';

  const qState = getQuestionState(state, question.id);
  const correctAnswer = question.answers.find((a) => a.isCorrect);

  for (const answer of question.answers) {
    const btn = document.createElement('button');
    btn.className = 'quiz-answer-btn';
    btn.dataset.answerId = answer.id;
    btn.textContent = answer.text;

    if (qState.resolved) {
      btn.disabled = true;
      if (answer.isCorrect) {
        btn.classList.add('correct');
      } else if (qState.attempts.includes(answer.id)) {
        btn.classList.add('wrong');
      }
    } else {
      // Not resolved yet — disable buttons that were already tried (wrong)
      if (qState.attempts.includes(answer.id)) {
        btn.disabled = true;
        btn.classList.add('wrong');
      }

      if (!qState.attempts.includes(answer.id)) {
        btn.addEventListener('click', () => {
          qState.attempts.push(answer.id);

          if (answer.isCorrect) {
            qState.resolved = true;
          } else if (qState.attempts.length >= state.maxAttempts) {
            qState.resolved = true;
          }

          rerender();
        });
      }
    }

    answersGrid.appendChild(btn);
  }

  section.appendChild(answersGrid);

  // Feedback / explanation area
  if (qState.attempts.length > 0) {
    if (qState.resolved) {
      // Fully resolved — show full explanation
      const lastAttempt = qState.attempts[qState.attempts.length - 1];
      const isCorrect = lastAttempt === correctAnswer?.id;

      const explanation = document.createElement('div');
      explanation.className = `quiz-explanation ${isCorrect ? 'correct' : 'wrong'}`;

      const icon = document.createElement('span');
      icon.className = 'quiz-explanation-icon';

      if (isCorrect) {
        icon.textContent = 'Správně!';
      } else {
        icon.textContent = `Správná odpověď je: ${correctAnswer?.text ?? ''}`;
      }

      explanation.appendChild(icon);

      if (question.explanation) {
        const text = document.createElement('p');
        text.className = 'quiz-explanation-text';
        text.textContent = question.explanation;
        explanation.appendChild(text);
      }

      section.appendChild(explanation);
    } else {
      // Not resolved yet, but has attempts — show attempt feedback
      const feedback = document.createElement('div');
      feedback.className = 'quiz-attempt-feedback';
      feedback.textContent = 'Špatně! Zkus to znovu.';
      section.appendChild(feedback);
    }
  }

  return section;
}

function buildResults(quiz: Quiz, state: QuizPlayerState): QuestionAttemptResult[] {
  return quiz.questions.map((question) => {
    const qState = getQuestionState(state, question.id);
    const correctId = question.answers.find((a) => a.isCorrect)?.id;
    const lastAttempt = qState.attempts[qState.attempts.length - 1];
    const isCorrect = lastAttempt === correctId;
    const points = isCorrect ? Math.max(0, MAX_ATTEMPTS + 1 - qState.attempts.length) : 0;

    return {
      questionId: question.id,
      attempts: [...qState.attempts],
      correct: isCorrect,
      points,
    };
  });
}

function createNavigation(
  quiz: Quiz,
  state: QuizPlayerState,
  onComplete: OnQuizComplete,
  rerender: () => void,
): HTMLElement {
  const nav = document.createElement('nav');
  nav.className = 'quiz-nav';

  const prevBtn = document.createElement('button');
  prevBtn.className = 'btn btn-ghost';
  prevBtn.textContent = 'Předchozí';
  prevBtn.disabled = state.currentIndex === 0;
  prevBtn.addEventListener('click', () => {
    state.currentIndex--;
    rerender();
  });

  const isLast = state.currentIndex === quiz.questions.length - 1;
  const currentQuestion = quiz.questions[state.currentIndex];
  const qState = getQuestionState(state, currentQuestion.id);
  const allResolved = countUnresolved(quiz, state) === 0;

  const nextBtn = document.createElement('button');

  if (isLast && allResolved) {
    // All questions resolved and on last question — show evaluate
    nextBtn.className = 'btn btn-success';
    nextBtn.textContent = 'Vyhodnotit';
    nextBtn.addEventListener('click', () => {
      onComplete(buildResults(quiz, state));
    });
  } else if (qState.resolved) {
    // Current question resolved — show "Další" or navigate
    nextBtn.className = 'btn btn-primary';
    nextBtn.textContent = 'Další';
    nextBtn.addEventListener('click', () => {
      if (isLast) {
        state.currentIndex = findFirstUnresolvedIndex(quiz, state);
      } else {
        state.currentIndex++;
      }
      rerender();
    });
  } else {
    // Not resolved — show skip button
    nextBtn.className = 'btn btn-primary';
    nextBtn.textContent = 'Přeskočit';
    nextBtn.addEventListener('click', () => {
      if (isLast) {
        state.currentIndex = findFirstUnresolvedIndex(quiz, state);
      } else {
        state.currentIndex++;
      }
      rerender();
    });
  }

  nav.appendChild(prevBtn);
  nav.appendChild(nextBtn);

  // Skip banner — show when wrapping around
  if (isLast && !allResolved) {
    const unresolved = countUnresolved(quiz, state);
    const banner = document.createElement('div');
    banner.className = 'quiz-skip-banner';
    banner.textContent = `Máš ${String(unresolved)} nezodpovězených otázek`;
    nav.appendChild(banner);
  }

  return nav;
}
