import type { Quiz } from '../types/quiz';
import { save, load } from './local-storage';

const CUSTOM_QUIZZES_KEY = 'custom_quizzes';

/** Save a custom quiz to localStorage. Appends to existing list. */
export function saveCustomQuiz(quiz: Quiz): void {
  const existing = loadCustomQuizzes();
  existing.push(quiz);
  save(CUSTOM_QUIZZES_KEY, existing);
}

/** Load all custom quizzes from localStorage. */
export function loadCustomQuizzes(): Quiz[] {
  return load<Quiz[]>(CUSTOM_QUIZZES_KEY) ?? [];
}

/** Delete a custom quiz by ID. */
export function deleteCustomQuiz(id: string): void {
  const existing = loadCustomQuizzes();
  const filtered = existing.filter((q) => q.id !== id);
  save(CUSTOM_QUIZZES_KEY, filtered);
}
