import type { QuizResult } from '../types/quiz';
import { loadResults } from './results-screen';
import { quizRegistry } from '../content/registry';

/** Callback when user exits the stats screen. */
export type OnStatsExit = () => void;

interface QuizStats {
  quizId: string;
  title: string;
  attempts: number;
  bestPercent: number;
  averagePercent: number;
  lastPercent: number;
  trend: 'up' | 'down' | 'same';
}

/** Calculate per-quiz statistics from a list of results. */
export function calculateQuizStats(results: QuizResult[]): QuizStats[] {
  const grouped = new Map<string, QuizResult[]>();

  for (const result of results) {
    const existing = grouped.get(result.quizId) ?? [];
    existing.push(result);
    grouped.set(result.quizId, existing);
  }

  const stats: QuizStats[] = [];

  for (const [quizId, quizResults] of grouped) {
    const quiz = quizRegistry.find((q) => q.id === quizId);
    const title = quiz?.title ?? quizId;

    const sorted = [...quizResults].sort((a, b) => a.completedAt - b.completedAt);
    const percentages = sorted.map((r) => Math.round((r.score / (r.maxScore || r.totalQuestions)) * 100));

    const bestPercent = Math.max(...percentages);
    const averagePercent = Math.round(
      percentages.reduce((sum, p) => sum + p, 0) / percentages.length,
    );
    const lastPercent = percentages[percentages.length - 1];

    let trend: 'up' | 'down' | 'same' = 'same';
    if (percentages.length >= 2) {
      const previous = percentages[percentages.length - 2];
      const last = percentages[percentages.length - 1];
      if (last > previous) {
        trend = 'up';
      } else if (last < previous) {
        trend = 'down';
      }
    }

    stats.push({
      quizId,
      title,
      attempts: quizResults.length,
      bestPercent,
      averagePercent,
      lastPercent,
      trend,
    });
  }

  return stats;
}

/** Get the trend arrow symbol. */
function getTrendSymbol(trend: 'up' | 'down' | 'same'): string {
  if (trend === 'up') return '\u2191';
  if (trend === 'down') return '\u2193';
  return '\u2192';
}

/** Get the CSS class for a trend direction. */
function getTrendClass(trend: 'up' | 'down' | 'same'): string {
  if (trend === 'up') return 'stats-trend-up';
  if (trend === 'down') return 'stats-trend-down';
  return 'stats-trend-same';
}

/** Render the statistics screen showing quiz history and progress. */
export function renderStatsScreen(container: HTMLElement, onExit: OnStatsExit): void {
  const wrapper = document.createElement('div');
  wrapper.className = 'stats-screen';

  const results = loadResults();

  // Header
  const header = document.createElement('header');
  header.className = 'stats-header';

  const title = document.createElement('h1');
  title.className = 'stats-title';
  title.textContent = 'Statistiky';

  const subtitle = document.createElement('p');
  subtitle.className = 'stats-subtitle';
  subtitle.textContent = 'Tv\u016Fj p\u0159ehled';

  header.appendChild(title);
  header.appendChild(subtitle);
  wrapper.appendChild(header);

  if (results.length === 0) {
    const empty = document.createElement('p');
    empty.className = 'stats-empty';
    empty.textContent = 'Zat\u00EDm \u017E\u00E1dn\u00E9 v\u00FDsledky. Zkus si prvn\u00ED kv\u00EDz!';
    wrapper.appendChild(empty);
  } else {
    // Summary cards
    const totalQuizzes = results.length;
    const totalQuestions = results.reduce((sum, r) => sum + r.totalQuestions, 0);
    const averageScore = Math.round(
      results.reduce((sum, r) => sum + (r.score / (r.maxScore || r.totalQuestions)) * 100, 0) / results.length,
    );

    const summary = document.createElement('div');
    summary.className = 'stats-summary';

    summary.appendChild(createSummaryCard(String(totalQuizzes), 'kv\u00EDz\u016F'));
    summary.appendChild(createSummaryCard(`${String(averageScore)}%`, 'pr\u016Fm\u011Br'));
    summary.appendChild(createSummaryCard(String(totalQuestions), 'ot\u00E1zek'));

    wrapper.appendChild(summary);

    // Per-quiz breakdown
    const quizStats = calculateQuizStats(results);
    const quizList = document.createElement('div');
    quizList.className = 'stats-quiz-list';

    for (const stat of quizStats) {
      quizList.appendChild(createQuizCard(stat));
    }

    wrapper.appendChild(quizList);
  }

  // Actions
  const actions = document.createElement('div');
  actions.className = 'stats-actions';

  const backBtn = document.createElement('button');
  backBtn.className = 'btn btn-ghost';
  backBtn.textContent = 'Zp\u011Bt na \u00FAvod';
  backBtn.addEventListener('click', onExit);

  actions.appendChild(backBtn);
  wrapper.appendChild(actions);

  container.appendChild(wrapper);
}

function createSummaryCard(value: string, label: string): HTMLElement {
  const card = document.createElement('div');
  card.className = 'stats-card';

  const valueEl = document.createElement('div');
  valueEl.className = 'stats-card-value';
  valueEl.textContent = value;

  const labelEl = document.createElement('div');
  labelEl.className = 'stats-card-label';
  labelEl.textContent = label;

  card.appendChild(valueEl);
  card.appendChild(labelEl);

  return card;
}

function createQuizCard(stat: QuizStats): HTMLElement {
  const card = document.createElement('div');
  card.className = 'stats-quiz-card';

  const titleEl = document.createElement('div');
  titleEl.className = 'stats-quiz-title';
  titleEl.textContent = stat.title;
  card.appendChild(titleEl);

  const rows: [string, string][] = [
    ['Po\u010Det pokus\u016F', String(stat.attempts)],
    ['Nejlep\u0161\u00ED', `${String(stat.bestPercent)}%`],
    ['Pr\u016Fm\u011Br', `${String(stat.averagePercent)}%`],
    ['Posledn\u00ED', `${String(stat.lastPercent)}%`],
  ];

  for (const [label, value] of rows) {
    const row = document.createElement('div');
    row.className = 'stats-quiz-row';

    const labelSpan = document.createElement('span');
    labelSpan.textContent = label;

    const valueSpan = document.createElement('span');
    valueSpan.textContent = value;

    row.appendChild(labelSpan);
    row.appendChild(valueSpan);
    card.appendChild(row);
  }

  // Trend row
  const trendRow = document.createElement('div');
  trendRow.className = 'stats-quiz-row';

  const trendLabel = document.createElement('span');
  trendLabel.textContent = 'Trend';

  const trendValue = document.createElement('span');
  trendValue.className = getTrendClass(stat.trend);
  trendValue.textContent = getTrendSymbol(stat.trend);

  trendRow.appendChild(trendLabel);
  trendRow.appendChild(trendValue);
  card.appendChild(trendRow);

  return card;
}
